import React from 'react';
import { Page} from '../../Pages';
import Home from '../../Pages/Home';
import Error from '../../Pages/Error';

interface Route   {
    path: string,
    element: React.ReactNode,
  }

interface RouteMapper {
  getRoutes: (array: Page[]) => Route[],
}

const routeMapper: RouteMapper = {
    getRoutes: (array) => {
        const paths: Route[] = array.map((e) => ({ path: e.name.toLowerCase(), element: e.element }))
        // paths.push({path: '/', element: <Home/> })
        // paths.push({path: '/*', element: <Error/> })
        return paths;
    }
}

export default routeMapper;
